import{_ as i,o as a,c as t,ag as r}from"./chunks/framework.CQYuu_FX.js";const p=JSON.parse('{"title":"POSLA 店舗運用手順書 — 全体目次","description":"","frontmatter":{},"headers":[],"relativePath":"operations/00-table-of-contents.md","filePath":"operations/00-table-of-contents.md"}'),e={name:"operations/00-table-of-contents.md"};function o(n,l,h,s,u,P){return a(),t("div",null,[...l[0]||(l[0]=[r('<h1 id="posla-店舗運用手順書-—-全体目次" tabindex="-1">POSLA 店舗運用手順書 — 全体目次 <a class="header-anchor" href="#posla-店舗運用手順書-—-全体目次" aria-label="Permalink to &quot;POSLA 店舗運用手順書 — 全体目次&quot;">​</a></h1><p><strong>対象読者</strong>: 飲食店オーナー / マネージャー / アルバイトスタッフ (ITリテラシー不問)</p><p><strong>書き方の方針</strong>:</p><ul><li>「設定タブを開く」ではなく <strong>「画面上部の左から4番目にある ⚙ マーク (歯車のアイコン) の【設定】ボタンをタップします」</strong> のように1クリック単位で記述</li><li>専門用語は初出時に必ず説明</li><li>失敗したときの対処法を必ず併記</li><li>初めて使う方でも、上から順番に読めば店舗運用の流れが分かる構成にしています</li></ul><hr><h2 id="全体構成" tabindex="-1">全体構成 <a class="header-anchor" href="#全体構成" aria-label="Permalink to &quot;全体構成&quot;">​</a></h2><h3 id="part-0-はじめに-—-posla-を使う前の準備" tabindex="-1">Part 0: はじめに — POSLA を使う前の準備 <a class="header-anchor" href="#part-0-はじめに-—-posla-を使う前の準備" aria-label="Permalink to &quot;Part 0: はじめに — POSLA を使う前の準備&quot;">​</a></h3><ul><li>0-1. 必要な機材一覧 (タブレット / スマホ / 店舗決済端末 / Wi-Fiルーター / プリンタ)</li><li>0-2. Wi-Fi の確認方法 (iPhone / Android / Windows それぞれ)</li><li>0-3. ブラウザの開き方と URL の入力方法</li><li>0-4. ログイン画面の開き方</li><li>0-5. ログインの仕方 (ユーザー名とパスワードの入力)</li><li>0-6. パスワードを忘れたときの対処法</li><li>0-7. 画面の見方 (タブ・ボタン・アイコンの名前と場所)</li><li>0-8. ロール (権限) の違い: オーナー / マネージャー / スタッフ / デバイス</li></ul><h3 id="part-1-毎日の営業-開店〜閉店" tabindex="-1">Part 1: 毎日の営業 (開店〜閉店) <a class="header-anchor" href="#part-1-毎日の営業-開店〜閉店" aria-label="Permalink to &quot;Part 1: 毎日の営業 (開店〜閉店)&quot;">​</a></h3><ul><li>1-1. 開店準備 <ul><li>1-1-1. KDS の電源を入れてログインする</li><li>1-1-2. レジの電源を入れてログインする</li><li>1-1-3. ハンディ端末の準備</li><li>1-1-4. 店頭決済端末の接続確認</li><li>1-1-5. プリンタの接続確認</li><li>1-1-6. レジを開ける (レジ開け操作の全手順)</li></ul></li><li>1-2. お客さんが来たとき <ul><li>1-2-1. テーブルに案内する (空席確認)</li><li>1-2-2. <strong>テーブル開放認証</strong> (📲 QR開放ボタンの押し方)</li><li>1-2-3. お客さんが QR コードを読み込む流れの説明</li><li>1-2-4. ハンディで注文を入れる (スタッフ側操作)</li></ul></li><li>1-3. キッチンでの操作 <ul><li>1-3-1. KDS 画面の見方 (受付 / 調理中 / 提供待ち)</li><li>1-3-2. 注文を「調理開始」にする</li><li>1-3-3. 調理が終わったら「提供待ち」にする</li><li>1-3-4. 音声コマンドで操作する方法 (「○○番提供」)</li></ul></li><li>1-4. 料理を提供する <ul><li>1-4-1. KDS で「提供済み」にする</li><li>1-4-2. テーブルの状態を確認する</li></ul></li><li>1-5. お会計 <ul><li>1-5-1. 現金でのお会計手順 (おつりの計算)</li><li>1-5-2. カードでのお会計手順 (外部カード端末で決済後、POSLAに記録)</li><li>1-5-3. QR決済 (PayPay/d払い) でのお会計手順</li><li>1-5-4. セルフレジ (お客さん自身のスマホ決済)</li><li>1-5-5. レシートの発行方法</li><li>1-5-6. 個別会計 (割り勘) の方法</li></ul></li><li>1-6. テイクアウト注文の処理</li><li>1-7. 品切れの設定と解除</li><li>1-8. ラストオーダーの設定</li><li>1-9. 閉店作業 <ul><li>1-9-1. レジを閉める (レジ締め操作の全手順)</li><li>1-9-2. 売上の確認方法</li><li>1-9-3. KDS / ハンディ / POSレジ端末の閉店時確認</li></ul></li></ul><h3 id="part-2-スタッフ管理" tabindex="-1">Part 2: スタッフ管理 <a class="header-anchor" href="#part-2-スタッフ管理" aria-label="Permalink to &quot;Part 2: スタッフ管理&quot;">​</a></h3><ul><li>2-1. 新しいスタッフのアカウントを作る</li><li>2-2. スタッフのパスワードをリセットする</li><li>2-3. スタッフを削除する (退職時)</li><li>2-4. <strong>デバイスアカウント</strong> (KDS / レジ / ハンディ専用) の作り方</li><li>2-5. シフトの作成と公開</li><li>2-6. 出退勤の打刻方法と確認</li><li>2-7. GPS 打刻の設定方法</li><li>2-8. AI シフト提案の使い方</li><li>2-9. 複数店舗のシフトヘルプ</li></ul><h3 id="part-3-メニュー管理" tabindex="-1">Part 3: メニュー管理 <a class="header-anchor" href="#part-3-メニュー管理" aria-label="Permalink to &quot;Part 3: メニュー管理&quot;">​</a></h3><ul><li>3-1. 新しいメニューを追加する</li><li>3-2. メニューの価格を変更する</li><li>3-3. メニューの写真を登録する</li><li>3-4. カテゴリの追加・並べ替え</li><li>3-5. オプション (トッピング等) の設定</li><li>3-6. 限定メニュー (店舗独自品) の追加</li><li>3-7. 多言語翻訳 (英語・中国語・韓国語) の実行</li><li>3-8. CSV でメニューを一括登録する</li><li>3-9. スマレジからメニューをインポートする</li><li>3-10. 本部メニューの管理 (チェーン店のみ)</li></ul><h3 id="part-4-売上とレポート" tabindex="-1">Part 4: 売上とレポート <a class="header-anchor" href="#part-4-売上とレポート" aria-label="Permalink to &quot;Part 4: 売上とレポート&quot;">​</a></h3><ul><li>4-1. 日次売上の見方</li><li>4-2. 商品別ランキングの見方</li><li>4-3. ABC 分析の見方</li><li>4-4. バスケット分析 (併売分析) の見方</li><li>4-5. 回転率・客層レポートの見方</li><li>4-6. スタッフ別評価レポート</li><li>4-7. 予約レポート (無断キャンセル率・キャンセル率)</li><li>4-8. クロス店舗レポート (オーナー向け)</li><li>4-9. CSV エクスポートの方法</li></ul><h3 id="part-5-予約管理" tabindex="-1">Part 5: 予約管理 <a class="header-anchor" href="#part-5-予約管理" aria-label="Permalink to &quot;Part 5: 予約管理&quot;">​</a></h3><ul><li>5-1. 予約 LP (お客様向けページ) の URL と QR の表示</li><li>5-2. ガント台帳の見方</li><li>5-3. 新しい予約を手動で入れる (電話受付)</li><li>5-4. Walk-in (予約なしの来店) を登録する</li><li>5-5. 予約客が来たとき (自動着席の仕組み)</li><li>5-6. 着席ボタンを使った手動着席</li><li>5-7. 無断キャンセルの登録</li><li>5-8. 予約の変更・キャンセル</li><li>5-9. コース予約の管理</li><li>5-10. 顧客台帳 (リピーター) の管理</li><li>5-11. VIP / ブラックリストの設定</li><li>5-12. 予約金 (デポジット) の設定と回収</li><li>5-13. AI 予約 (お客様の自由文入力) の仕組み</li><li>5-14. 予約リマインダーメールの設定</li></ul><h3 id="part-6-店舗の設定" tabindex="-1">Part 6: 店舗の設定 <a class="header-anchor" href="#part-6-店舗の設定" aria-label="Permalink to &quot;Part 6: 店舗の設定&quot;">​</a></h3><ul><li>6-1. 店舗情報の変更 (店名・住所・電話番号)</li><li>6-2. テーブルの追加・削除・レイアウト変更</li><li>6-3. QRコードの印刷 (テーブル / テイクアウト / 予約)</li><li>6-4. 営業時間・消費税率の設定</li><li>6-5. 決済方法の有効化・無効化</li><li>6-6. POSLA決済の設定 (セルフ会計 / テイクアウト)</li><li>6-7. ウェルカムメッセージの設定</li><li>6-8. テイクアウトの設定</li><li>6-9. <strong>プリンタ (Star/Epson) の設定</strong></li><li>6-10. 外観カスタマイズ (ロゴ・色)</li></ul><h3 id="part-7-契約・お支払い" tabindex="-1">Part 7: 契約・お支払い <a class="header-anchor" href="#part-7-契約・お支払い" aria-label="Permalink to &quot;Part 7: 契約・お支払い&quot;">​</a></h3><ul><li>7-1. サブスクリプション (月額契約) の開始</li><li>7-2. 契約内容の確認</li><li>7-3. 本部一括配信アドオンの追加</li><li>7-4. 解約の方法</li><li>7-5. 30日無料トライアル中のキャンセル</li></ul><h3 id="part-8-トラブルシューティング-困ったとき" tabindex="-1">Part 8: トラブルシューティング (困ったとき) <a class="header-anchor" href="#part-8-トラブルシューティング-困ったとき" aria-label="Permalink to &quot;Part 8: トラブルシューティング (困ったとき)&quot;">​</a></h3><ul><li>8-1. ログインできない</li><li>8-2. 注文が入らない / 画面が動かない</li><li>8-3. KDS に注文が表示されない</li><li>8-4. 店頭決済端末が反応しない</li><li>8-5. Wi-Fi が切れた / インターネットに繋がらない</li><li>8-6. お客さんの QR コードが読めない</li><li>8-7. 間違えて注文を入れてしまった</li><li>8-8. 返金が必要なとき</li><li>8-9. パスワードがわからなくなった</li><li>8-10. 画面が真っ白 / エラーが出る</li><li>8-11. プリンタが印刷しない</li><li>8-12. 予約が反映されない / 自動着席しない</li></ul><h3 id="付録" tabindex="-1">付録 <a class="header-anchor" href="#付録" aria-label="Permalink to &quot;付録&quot;">​</a></h3><ul><li>A. 用語集 (POSLAで使う言葉の辞書)</li><li>B. ショートカット・便利機能一覧</li><li>C. 推奨機材と購入先リンク</li><li>D. サポートガイド (非AI) の使い方</li><li>E. 動画チュートリアル一覧 (将来)</li></ul><hr><h2 id="読み進め方" tabindex="-1">読み進め方 <a class="header-anchor" href="#読み進め方" aria-label="Permalink to &quot;読み進め方&quot;">​</a></h2><p>初めてPOSLAを使う場合は、Part 0 から順番に読んでください。すでに運用中の場合は、困っている操作に近いPartを開いて確認してください。</p><p>店舗スタッフに共有する場合は、まず Part 1「毎日の営業」と Part 8「トラブルシューティング」を案内すると、日々の営業で必要な操作を把握しやすくなります。</p>',30)])])}const c=i(e,[["render",o]]);export{p as __pageData,c as default};
